import torch
import torch.nn as nn


class Model(nn.Module):
    def __init__(self, in_features, n_classes, cutoffs, div_value, head_bias):
        super().__init__()
        self.adaptive_logsoftmax = nn.AdaptiveLogSoftmaxWithLoss(
            in_features, n_classes, cutoffs, div_value=div_value, head_bias=head_bias
        )

    def forward(self, x, target):
        loss, output = self.adaptive_logsoftmax(x, target)
        return torch.sum(loss)


